      canvas.width = container.clientWidth;
      canvas.height = container.clientHeight;
    };
    window.addEventListener('resize', resize);
    resize();

    // 3D Point Projection Helper
    const project = (x: number, y: number, z: number, w: number, h: number) => {
      const fov = 250;
      const scale = fov / (fov + z + 200); // Camera distance offset
      return {
        x: x * scale + w / 2,
        y: y * scale + (h / 2) - 10, // Slight vertical offset
        scale: scale
      };
    };

    // Initialize Sphere Particles
    const particles: { x: number; y: number; z: number }[] = [];
    const numParticles = 250;
    const radius = 90;

    for (let i = 0; i < numParticles; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos((Math.random() * 2) - 1);
      particles.push({
        x: radius * Math.sin(phi) * Math.cos(theta),
        y: radius * Math.sin(phi) * Math.sin(theta),
        z: radius * Math.cos(phi)
      });
    }

    const draw = () => {
      if (!ctx || !canvas) return;
      time += 0.015;
      const w = canvas.width;
      const h = canvas.height;

      // Clear with trail effect (Phosphor persistence)
      ctx.fillStyle = 'rgba(9, 9, 11, 0.25)'; 
      ctx.fillRect(0, 0, w, h);

      // Draw Grid
      ctx.strokeStyle = 'rgba(39, 39, 42, 0.3)';
      ctx.lineWidth = 1;
      const gridSize = 40;

      // Vertical lines
      for (let x = (w / 2) % gridSize; x < w; x += gridSize) {
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, h);
        ctx.stroke();
      }
      for (let x = (w / 2) % gridSize; x > 0; x -= gridSize) {
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, h);
        ctx.stroke();
      }
      // Horizontal lines
      for (let y = (h / 2) % gridSize; y < h; y += gridSize) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(w, y);
        ctx.stroke();
      }
      for (let y = (h / 2) % gridSize; y > 0; y -= gridSize) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(w, y);
        ctx.stroke();
      }

      // --- 3D ROTATING SPHERE (Sovereign Mirror) ---
      const rotX = time * 0.4;
      const rotY = time * 0.2;

      ctx.fillStyle = '#10b981'; // Emerald

      particles.forEach((p, i) => {
        // Rotate Y
        let x1 = p.x * Math.cos(rotY) - p.z * Math.sin(rotY);
        let z1 = p.x * Math.sin(rotY) + p.z * Math.cos(rotY);

        // Rotate X
        let y1 = p.y * Math.cos(rotX) - z1 * Math.sin(rotX);
        let z2 = p.y * Math.sin(rotX) + z1 * Math.cos(rotX);

        // Project
        const proj = project(x1, y1, z2, w, h);

        // Draw Particle
        // Depth-based opacity
        const alpha = Math.max(0.1, (z2 + radius) / (radius * 2));
        ctx.fillStyle = `rgba(16, 185, 129, ${alpha})`;

        ctx.beginPath();
        ctx.arc(proj.x, proj.y, 1.5 * proj.scale, 0, Math.PI * 2);
        ctx.fill();

        // Occasional connections (Constellation effect)
        if (i % 15 === 0) {
            ctx.strokeStyle = `rgba(16, 185, 129, ${alpha * 0.3})`;
            ctx.beginPath();
            ctx.moveTo(proj.x, proj.y);
            ctx.lineTo(w/2, h/2 - 10); // Connect to core
            ctx.stroke();
        }
      });


      // --- OSCILLOSCOPE WAVE (Phonon Tax) ---
      const waveY = h - 40;
      ctx.beginPath();
      ctx.moveTo(0, waveY);

      for (let x = 0; x < w; x += 3) {
        // Sum of sines for interesting interference
        const y = waveY + 
          Math.sin(x * 0.02 + time * 3) * 15 * Math.sin(time) +
          Math.cos(x * 0.05 - time * 2) * 8;
        ctx.lineTo(x, y);
      }

      ctx.strokeStyle = '#10b981';
      ctx.lineWidth = 2;
      ctx.shadowBlur = 8;
      ctx.shadowColor = '#10b981';
      ctx.stroke();
      ctx.shadowBlur = 0;

      // Reflection of wave (Ghosting)
      ctx.beginPath();
      ctx.moveTo(0, waveY);
      for (let x = 0; x < w; x += 5) {
         const y = waveY + Math.sin(x * 0.02 + time * 3 + 0.5) * 15 * Math.sin(time);
         ctx.lineTo(x, y);
      }
      ctx.strokeStyle = 'rgba(16, 185, 129, 0.2)';
      ctx.lineWidth = 1;
      ctx.stroke();

      // --- SCANLINES ---
      ctx.fillStyle = 'rgba(0, 0, 0, 0.15)';
      for (let y = 0; y < h; y += 3) {
        ctx.fillRect(0, y, w, 1);
      }

      animationFrameId = requestAnimationFrame(draw);
    };

    draw();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <div ref={containerRef} className="w-full h-full relative bg-zinc-950 overflow-hidden rounded-xl border border-zinc-800 shadow-[inset_0_0_20px_rgba(0,0,0,0.8)]">
      <canvas ref={canvasRef} className="block w-full h-full" />

      {/* UI Overlays */}
      <div className="absolute top-3 left-3 flex flex-col gap-1 pointer-events-none">
        <div className="flex items-center gap-2">
            <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_5px_#10b981]" />
            <span className="text-[10px] font-mono text-emerald-400 font-bold tracking-widest">LIVE_FEED :: OSC_1</span>
        </div>
        <span className="text-[9px] font-mono text-zinc-600 pl-4">FREQ: 432.09 Hz // RESONANCE: STABLE</span>
      </div>

      <div className="absolute bottom-3 right-3 text-[9px] font-mono text-emerald-500/50 pointer-events-none text-right">
        <div>PHONON_TAX_VISUALIZER_V1.0</div>
        <div>DELTA_TRIODE: CONNECTED</div>
      </div>
    </div>
  );
};

