      // Ripple Logic
      let rippleForce = 0;
      let rippleRadius = 0;
      if (rippleRef.current.active) {
        const elapsed = performance.now() - rippleRef.current.startTime;
        rippleRadius = elapsed * 0.3; 
        const life = Math.max(0, 1 - elapsed / 1200);
        if (life <= 0) rippleRef.current.active = false;
        rippleForce = life;
      }

      // --- 3D ROTATING SPHERE ---
      const rotX = time * 0.4 * (freq / 50);
      const rotY = time * 0.2 * (freq / 50);

      // Resonance Jitter
      const jitterAmount = (100 - res) * 0.08;

      particles.forEach((p, i) => {
