            <span className={`text-[10px] font-mono font-bold tracking-widest ${resonance < 50 ? 'text-red-400' : 'text-emerald-400'}`}>
                LIVE_FEED :: {resonance < 50 ? 'UNSTABLE' : 'LOCKED'}
